import { useState } from "react";
import { analyzeWriting } from "../../ai/aiService";

export default function AIWritingAssistant({ title, content }) {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleAnalyze = async () => {
    if (!title.trim() || !content.trim()) {
      setError("Please add title & content first.");
      return;
    }

    setLoading(true);
    setError("");

    try {
      const data = await analyzeWriting(title, content);
      setResult(data);
    } catch (e) {
      setError("AI failed. Try again.");
    }

    setLoading(false);
  };

  const score = result?.score || 0;

  return (
    <div style={s.wrapper}>
      {/* BUTTON */}
      <button style={s.button} onClick={handleAnalyze}>
        {loading ? "Analyzing..." : "✨ Analyze with AI"}
      </button>

      {error && <div style={s.error}>{error}</div>}

      {/* RESULT */}
      {result && (
        <div style={s.card}>
          {/* HEADER */}
          <div style={s.header}>
            <h3 style={s.title}>Writing Analysis</h3>
            <span style={s.score}>{score}/10</span>
          </div>

          {/* META */}
          <div style={s.meta}>
            <div style={s.metaItem}>
              <span>🎯 Tone</span>
              <strong>{result.tone}</strong>
            </div>
            <div style={s.metaItem}>
              <span>📖 Readability</span>
              <strong>{result.readability}</strong>
            </div>
          </div>

          {/* INTRO */}
          <div style={s.section}>
            <h4>💡 Better Opening</h4>
            <p>{result.rewrittenIntro}</p>
          </div>

          {/* GRID */}
          <div style={s.grid}>
            <div>
              <h4>✅ Strengths</h4>
              {result.strengths.map((s_, i) => (
                <p key={i}>• {s_}</p>
              ))}
            </div>

            <div>
              <h4>🔧 Improvements</h4>
              {result.improvements.map((i_, idx) => (
                <p key={idx}>• {i_}</p>
              ))}
            </div>
          </div>

          <div style={s.footer}>Powered by AI</div>
        </div>
      )}
    </div>
  );
}

const s = {
  wrapper: {
    marginTop: 16,
  },

  button: {
    width: "100%",
    padding: "12px",
    background: "linear-gradient(135deg, #2563eb, #1e40af)",
    color: "#fff",
    border: "none",
    borderRadius: 10,
    fontWeight: 700,
    cursor: "pointer",
    fontSize: 14,
  },

  error: {
    marginTop: 10,
    padding: 10,
    background: "#fee2e2",
    color: "#dc2626",
    borderRadius: 8,
    fontSize: 13,
  },

  card: {
    marginTop: 16,
    padding: 18,
    borderRadius: 14,
    background: "#ffffff",
    boxShadow: "0 10px 30px rgba(0,0,0,0.08)",
    border: "1px solid #e5e7eb",
  },

  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    marginBottom: 12,
  },

  title: {
    fontSize: 16,
    fontWeight: 700,
  },

  score: {
    background: "#1d4ed8",
    color: "#fff",
    padding: "4px 10px",
    borderRadius: 8,
    fontWeight: 700,
    fontSize: 12,
  },

  meta: {
    display: "flex",
    gap: 16,
    marginBottom: 12,
  },

  metaItem: {
    display: "flex",
    flexDirection: "column",
    fontSize: 13,
  },

  section: {
    background: "#f8fafc",
    padding: 10,
    borderRadius: 8,
    marginBottom: 12,
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: 12,
  },

  footer: {
    marginTop: 10,
    fontSize: 11,
    color: "#6b7280",
    textAlign: "center",
  },
};
